UPDATE public.settings SET value = '[{"id":"resp_ft","text":"Anh/chị có thường xuyên mua sắm quần áo trực tuyến không?","textEN":"Do you frequently shop for clothes online?","type":"radio","options":["Có","Không"],"optionsEN":["Yes","No"],"required":true,"section":"Thông tin chung","order":1},{"id":"resp_eval","text":"Anh/chị đã từng sử dụng công cụ hỗ trợ gợi ý trang phục bằng AI (AI Stylist) nào chưa?","textEN":"Have you ever used an AI fashion stylist or recommendation tool?","type":"radio","options":["Có","Không"],"optionsEN":["Yes","No"],"required":true,"section":"Thông tin chung","order":2},{"id":"resp_ai_dev","text":"Anh/chị có quan tâm đến thời trang bền vững, quần áo tái chế (upcycling) không?","textEN":"Are you interested in sustainable fashion or upcycled clothing?","type":"radio","options":["Có","Không"],"optionsEN":["Yes","No"],"required":true,"section":"Thông tin chung","order":3},{"id":"resp_gender","text":"Giới tính","textEN":"Gender","type":"radio","options":["Nam","Nữ","Khác","Không muốn trả lời"],"optionsEN":["Male","Female","Other","Prefer not to say"],"required":true,"section":"Thông tin chung","order":4},{"id":"resp_age","text":"Độ tuổi","textEN":"Age","type":"radio","options":["18-24","25-34","35-44","45-54","Từ 55 trở lên"],"optionsEN":["18-24","25-34","35-44","45-54","55 and above"],"required":true,"section":"Thông tin chung","order":5},{"id":"resp_region","text":"Khu vực sinh sống","textEN":"Living region","type":"radio","options":["TP.HCM","Hà Nội","Miền Bắc khác","Miền Trung - Tây Nguyên","Miền Nam khác"],"optionsEN":["HCMC","Hanoi","Other North","Central - Highlands","Other South"],"required":true,"section":"Thông tin chung","order":6},{"id":"resp_dept","text":"Phong cách thời trang yêu thích của Anh/chị là gì?","textEN":"What is your preferred fashion style?","type":"radio","options":["Thường ngày (Casual)","Công sở (Formal)","Cổ điển (Vintage)","Thể thao (Sporty)","Đường phố (Streetwear)","Khác"],"optionsEN":["Casual","Formal","Vintage","Sporty","Streetwear","Other"],"required":true,"section":"Thông tin chung","order":7},{"id":"resp_experience","text":"Tần suất mua sắm quần áo của Anh/chị?","textEN":"How often do you shop for clothes?","type":"radio","options":["Hàng tuần","Hàng tháng","Vài tháng một lần","Chỉ khi cần thiết","Khác"],"optionsEN":["Weekly","Monthly","Every few months","Only when needed","Other"],"required":true,"section":"Thông tin chung","order":8},{"id":"FC1","text":"Tôi lo ngại bị mất hình ảnh trước người khác nếu trang phục do AI gợi ý không phù hợp với tôi.","textEN":"I would be concerned about losing my fashion image if the outfits recommended by the AI did not suit me.","type":"likert","section":"Câu hỏi ban đầu","order":9},{"id":"FC2","text":"Tôi quan tâm đến việc bảo vệ phong cách thời trang cá nhân của mình khi sử dụng gợi ý từ AI Stylist.","textEN":"I care about protecting my personal style when receiving recommendations from the AI Stylist.","type":"likert","section":"Câu hỏi ban đầu","order":10},{"id":"FC3","text":"Tôi lo ngại người khác sẽ đánh giá tiêu cực hoặc cho rằng tôi có gu thời trang kém nếu mặc đồ tái chế (upcycling) từ ReFashion.","textEN":"I worry that others would judge me negatively or think I have poor style if I wore upcycled clothes from ReFashion.","type":"likert","section":"Câu hỏi ban đầu","order":11},{"id":"FC4","text":"Việc duy trì hình ảnh cá nhân chỉn chu và phong cách là quan trọng đối với tôi khi chọn trang phục.","textEN":"Maintaining a neat and stylish personal image is important to me when selecting outfits.","type":"likert","section":"Câu hỏi ban đầu","order":12},{"id":"MC_TBD1","text":"Giao diện gợi ý của AI Stylist dường như được thiết kế để cung cấp thông tin minh bạch ngay từ đầu.","textEN":"The AI Stylist recommendation interface appears to be designed with transparency from the outset.","type":"likert","section":"MC: Minh bạch","order":13},{"id":"MC_TBD2","text":"Thông tin giải thích hoặc Hộ chiếu Số DPP dường như là một phần không thể thiếu của hệ thống tư vấn thời trang này.","textEN":"The styling explanation or DPP Passport seems to be integrated as an essential part of this styling system.","type":"likert","section":"MC: Minh bạch","order":14},{"id":"MC_TBD3","text":"Hệ thống cung cấp thông tin rõ ràng về các sản phẩm và dữ liệu nguồn gốc.","textEN":"The system provides clear information about the products and their sustainability provenance.","type":"likert","section":"MC: Minh bạch","order":15},{"id":"MC_TBD4","text":"Hệ thống giải thích rõ lý do hoặc tiêu chí vì sao bộ outfit này phù hợp với tôi.","textEN":"The system clearly explains the reasons or criteria why this outfit suits me.","type":"likert","section":"MC: Minh bạch","order":16},{"id":"MC_TBD5","text":"Hệ thống cung cấp lời giải thích dễ hiểu (XAI) cho các gợi ý trang phục.","textEN":"The system provides understandable explanations (XAI) for outfit recommendations.","type":"likert","section":"MC: Minh bạch","order":17},{"id":"MC_TBD6","text":"Hệ thống truyền đạt rõ ràng nguồn gốc và vòng đời sản phẩm thông qua Hộ chiếu Số DPP.","textEN":"The system clearly communicates product origin and lifecycle via the Digital Product Passport (DPP).","type":"likert","section":"MC: Minh bạch","order":18},{"id":"MC_TBD7","text":"Hệ thống giúp tôi dễ dàng xác thực tính chính xác của dữ liệu thời trang bền vững.","textEN":"The system helps me easily verify the reliability of sustainable fashion claims.","type":"likert","section":"MC: Minh bạch","order":19},{"id":"MC_OF1","text":"Outfit gợi ý mà tôi nhận được từ AI Stylist là rất phù hợp và đẹp mắt.","textEN":"The styling recommendations I received from the AI Stylist are favorable and appealing.","type":"likert","section":"MC: Kết quả","order":20},{"id":"MC_OF2","text":"Các sản phẩm thời trang tái chế được đề xuất này rất có ích cho nhu cầu phối đồ của tôi.","textEN":"These recommended upcycled fashion items are beneficial for my wardrobe coordination.","type":"likert","section":"MC: Kết quả","order":21},{"id":"MC_OF3","text":"Gu phối đồ từ AI Stylist này đúng với những gì tôi mong muốn.","textEN":"The styling suggestions from the AI Stylist match what I desired.","type":"likert","section":"MC: Kết quả","order":22},{"id":"RA1","text":"Tôi cảm thấy hệ thống AI Stylist là một trợ lý phù hợp để tư vấn phong cách thời trang.","textEN":"I feel the AI system is an appropriate agent to support fashion styling tasks.","type":"likert","section":"Role Appropriateness","order":23},{"id":"RA2","text":"Vai trò của AI trong việc phân tích phong cách và đề xuất trang phục là hợp lý.","textEN":"The role of AI in this styling recommendation process is appropriate.","type":"likert","section":"Role Appropriateness","order":24},{"id":"RA3","text":"Việc AI tham gia hỗ trợ phối đồ phù hợp với kỳ vọng của tôi về ứng dụng công nghệ trong thời trang.","textEN":"AI participation in coordinate recommendation aligns with my expectations of technology in fashion.","type":"likert","section":"Role Appropriateness","order":25},{"id":"PF1","text":"Tôi có cơ hội tự chọn các sản phẩm làm đầu vào để điều chỉnh gợi ý của AI Stylist.","textEN":"I have the opportunity to select input products to customize the AI Stylist''s recommendations.","type":"likert","section":"Procedural Fairness","order":26},{"id":"PF2","text":"Tôi có thể dễ dàng yêu cầu gợi ý lại (Reset) nếu kết quả không phản ánh đúng gu của tôi.","textEN":"I can easily reset and ask for new recommendations if the results do not reflect my style.","type":"likert","section":"Procedural Fairness","order":27},{"id":"PF3","text":"Quy trình gợi ý trang phục của AI được áp dụng nhất quán.","textEN":"The recommendation process is applied consistently.","type":"likert","section":"Procedural Fairness","order":28},{"id":"PF4","text":"Quy trình gợi ý giúp giảm định kiến và cá nhân hóa đúng nhu cầu.","textEN":"The recommendation process helps personalize styling without biases.","type":"likert","section":"Procedural Fairness","order":29},{"id":"PF5","text":"Quy trình gợi ý dựa trên thông tin thời trang phù hợp và liên quan.","textEN":"The recommendation process is based on relevant fashion and styling information.","type":"likert","section":"Procedural Fairness","order":30},{"id":"PF6","text":"Quy trình gợi ý và Hộ chiếu Số DPP tuân thủ các chuẩn mực đạo đức về môi trường và lao động.","textEN":"The recommendation process and DPP comply with ethical and environmental standards.","type":"likert","section":"Procedural Fairness","order":31},{"id":"CT1","text":"Tôi tin rằng hệ thống AI Stylist hoạt động tốt trong việc hỗ trợ phối đồ.","textEN":"I believe the AI system performs well in supporting style coordination.","type":"likert","section":"Cognitive Trust","order":32},{"id":"CT2","text":"Tôi tin rằng hệ thống AI Stylist có năng lực cần thiết để đưa ra gợi ý thời trang chất lượng.","textEN":"I believe the AI system has the necessary competence to suggest high-quality outfits.","type":"likert","section":"Cognitive Trust","order":33},{"id":"CT3","text":"Tôi tin rằng hệ thống AI Stylist xử lý thông tin sở thích của tôi một cách đáng tin cậy.","textEN":"I believe the AI system processes my style preferences reliably.","type":"likert","section":"Cognitive Trust","order":34},{"id":"CT4","text":"Tôi tin rằng hệ thống AI Stylist áp dụng tiêu chí lựa chọn nhất quán khi đề xuất outfit.","textEN":"I believe the AI system applies styling criteria consistently when suggesting outfits.","type":"likert","section":"Cognitive Trust","order":35},{"id":"DA1","text":"Tôi sẵn sàng chấp nhận các đề xuất trang phục do AI Stylist gợi ý.","textEN":"I am willing to accept the outfit recommendations provided by the AI Stylist.","type":"likert","section":"Decision Acceptance","order":36},{"id":"DA2","text":"Tôi dự định sử dụng gợi ý của AI Stylist như một nguồn tham khảo hữu ích cho phong cách của mình.","textEN":"I intend to use the AI Stylist recommendations as a useful reference for my personal style.","type":"likert","section":"Decision Acceptance","order":37},{"id":"DA3","text":"Tôi sẵn sàng làm theo các tư vấn phối đồ do hệ thống AI Stylist cung cấp.","textEN":"I am willing to follow coordination advice provided by the AI Stylist.","type":"likert","section":"Decision Acceptance","order":38},{"id":"DA4","text":"Nếu nhãn hàng tiếp tục cung cấp AI Stylist này, tôi dự định sẽ tiếp tục sử dụng.","textEN":"If the brand continues to offer this AI Stylist, I intend to continue using it.","type":"likert","section":"Decision Acceptance","order":39},{"id":"DA5","text":"Tôi ủng hộ việc ứng dụng AI Stylist và Hộ chiếu Số DPP trong mua sắm thời trang.","textEN":"I tend to support the brand''s use of an AI Stylist and DPP in fashion shopping.","type":"likert","section":"Decision Acceptance","order":40},{"id":"DA6","text":"Tôi sẽ cân nhắc mua sắm các sản phẩm thời trang do hệ thống AI Stylist này gợi ý.","textEN":"I would consider purchasing the clothing items recommended by this AI Stylist system.","type":"likert","section":"Decision Acceptance","order":41},{"id":"CTRL_AI_FAM","text":"Mức độ am hiểu của Anh/chị về các hệ thống trí tuệ nhân tạo (AI)?","textEN":"How familiar are you with artificial intelligence (AI) systems?","type":"select","options":["Rất thấp","Thấp","Trung bình","Cao","Rất cao"],"optionsEN":["Very low","Low","Medium","High","Very high"],"required":true,"section":"Biến kiểm soát","order":42},{"id":"CTRL_AI_EXP","text":"Anh/chị đã từng sử dụng công cụ AI trong công việc hàng ngày chưa?","textEN":"Have you used AI tools in your daily work?","type":"select","options":["Chưa từng","Thỉnh thoảng","Thường xuyên"],"optionsEN":["Never","Occasionally","Regularly"],"required":true,"section":"Biến kiểm soát","order":43},{"id":"ATT1","text":"Trong gợi ý trang phục trên, tỷ lệ độ phù hợp (Match percentage) là bao nhiêu?","textEN":"In the above styling recommendation, what is the match percentage?","type":"text","required":true,"section":"Biến kiểm soát","order":44},{"id":"DETAIL_LEVEL","text":"Theo Anh/chị, gợi ý trang phục trên cung cấp mức độ thông tin chi tiết như thế nào?","textEN":"In your opinion, how detailed is the styling recommendation information provided above?","type":"likert","scaleStart":1,"scaleEnd":7,"labelStart":"Rất sơ sài","labelEnd":"Rất chi tiết","labelStartEN":"Very sketchy","labelEndEN":"Very detailed","required":true,"section":"Biến kiểm soát","order":45},{"id":"email","text":"Nếu Anh/chị có nhu cầu nhận kết quả của nghiên cứu này, chúng tôi sẵn sàng cung cấp sau khi hoàn thành, vui lòng nhập địa chỉ email của Anh/chị hoặc gõ \"Không\" nếu Anh/chị không có nhu cầu.","textEN":"If you wish to receive the results of this study, please enter your email address or type \"No\" if you do not want it.","type":"text","required":true,"section":"Biến kiểm soát","order":46}]'::jsonb WHERE key = 'hr_questions';